import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Fabric 與模組簡介","description":"Minecraft Java 版中 Fabric 和模組開發的簡要介紹。","frontmatter":{"title":"Fabric 與模組簡介","description":"Minecraft Java 版中 Fabric 和模組開發的簡要介紹。","authors":["IMB11","itsmiir"],"authors-nogithub":["basil4088"],"files":[]},"headers":[],"relativePath":"zh_tw/1.21.8/develop/getting-started/introduction-to-fabric-and-modding.md","filePath":"versions/1.21.8/translated/zh_tw/develop/getting-started/introduction-to-fabric-and-modding.md","lastUpdated":1760721669000}`);var a={name:`zh_tw/1.21.8/develop/getting-started/introduction-to-fabric-and-modding.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Fabric 與模組簡介 <a class="header-anchor" href="#h1" aria-label="Permalink to “Fabric 與模組簡介”">​</a></h1><h2 id="prerequisites" tabindex="-1">先決條件 <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “先決條件”">​</a></h2><p>在開始之前，你應該具備對於Java開發有基本了解，並理解物件導向程式設計（OOP）。</p><p>如果您不熟悉這些概念，建議您在開始模組開發之前，先參考一些關於 Java 和 OOP 的教學資源，以下是一些您可以用來學習 Java 和 OOP 的資源：</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3：Java 教學</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy：學習 Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3：Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium：OOP 簡介</a></li></ul><h3 id="terminology" tabindex="-1">術語 <a class="header-anchor" href="#terminology" aria-label="Permalink to “術語”">​</a></h3><p>在開始之前，讓我們先來了解一些使用 Fabric 進行模組開發時會遇到的術語：</p><ul><li><strong>模組 (Mod)</strong>：對遊戲的修改，可以加入新功能或變更現有功能。</li><li><strong>模組載入器 (Mod Loader)</strong>：將模組載入到遊戲中的工具，例如 Fabric Loader。</li><li><strong>Mixin</strong>：一種在執行時修改遊戲程式碼的工具。想要了解更多資訊，可以參考 <a href="https://fabricmc.net/wiki/tutorial:mixin_introduction" target="_blank" rel="noreferrer">Mixin 簡介</a>。</li><li><strong>Gradle</strong>：用於構建和編譯模組的自動化構建工具，Fabric 使用它來構建模組。</li><li><strong>映射 (Mappings)</strong>：將混淆程式碼轉換為人類可讀程式碼的映射集合。</li><li><strong>混淆 (Obfuscation)</strong>：使程式碼難以理解的過程，Mojang 使用它來保護 Minecraft 的程式碼。</li><li><strong>重新映射 (Remapping)</strong>：將混淆程式碼映射到人類可讀程式碼的過程。</li></ul><h2 id="what-is-fabric" tabindex="-1">什麼是 Fabric？ <a class="header-anchor" href="#what-is-fabric" aria-label="Permalink to “什麼是 Fabric？”">​</a></h2><p>Fabric 是一個輕量級的 Minecraft Java 版模組開發工具鏈。</p><p>它被設計成一個簡單易用的模組開發平台。 Fabric 是由社群驅動，並且開源的專案，這代表任何人都可以為 Fabric 做出貢獻。</p><p>你應該了解組成 Fabric 的四個主要部分：</p><ul><li><strong>Fabric Loader</strong>: 一個靈活、跨平台的模組載入器，專為 Minecraft 和其他遊戲及應用程式設計。</li><li><strong>Fabric Loom</strong>：Gradle 插件，讓開發者能夠輕鬆的開發模組及除錯。</li><li><strong>Fabric API</strong>：一組供模組開發者在建立模組時使用的 API 和工具。</li><li><strong>Yarn</strong>：一組開放的 Minecraft 映射，任何人都可以在 Creative Commons Zero 授權條款下免費使用。</li></ul><h2 id="why-is-fabric-necessary-to-mod-minecraft" tabindex="-1">為什麼需要 Fabric 來開發 Minecraft 模組？ <a class="header-anchor" href="#why-is-fabric-necessary-to-mod-minecraft" aria-label="Permalink to “為什麼需要 Fabric 來開發 Minecraft 模組？”">​</a></h2><blockquote><p>模組開發是指修改遊戲，以改變其行為或添加新功能的過程。對於 Minecraft 而言，這涵蓋的範圍很廣，從加入新的物品、方塊或實體，到改變遊戲的機制或加入新的遊戲模式，都在其中。</p></blockquote><p>Minecraft Java 版的程式碼被 Mojang 混淆，使得單獨進行模組開發並不容易。 然而，借助 Fabric 等模組開發工具，模組開發將變得更加容易。 有幾個映射系統可以協助進行模組開發。</p><p>Loom 使用這些映射將混淆的程式碼重新映射為人類可讀的格式，使模組開發者更容易理解與修改遊戲的程式碼。 Yarn 是一個流行且優秀的映射選擇，除此之外，還有其他的選擇。 每個映射專案都有其優勢或重點。</p><p>Loom 讓你可以輕鬆地針對重新映射的程式碼進行開發和編譯模組，而 Fabric Loader 則能讓你將這些模組載入到遊戲中。</p><h2 id="what-does-fabric-api-provide-and-why-is-it-needed" tabindex="-1">Fabric API 提供了什麼，為什麼需要它？ <a class="header-anchor" href="#what-does-fabric-api-provide-and-why-is-it-needed" aria-label="Permalink to “Fabric API 提供了什麼，為什麼需要它？”">​</a></h2><blockquote><p>Fabric API 是一組供模組開發者在建立模組時使用的 API 和工具。</p></blockquote><p>Fabric API 在Minecraft 現有功能的基礎上，提供了大量的 API。例如，它為模組開發人員提供新的Hook和事件，或提供新的實用程式和工具，例如存取擴展器 (Access Wideners) 以及存取內部登錄（例如可堆非物品登陸）的能力，使得模組開發更容易。</p><p>雖然 Fabric API 提供了強大的功能，但有些任務，例如基本的方塊登錄，可以使用原版 API 完成，而無需使用 Fabric API。</p>`,22)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};